const transactions = $input.all()[0].json;

const salaryTx = transactions
  .filter(t => t.amount > 1000 && t.applicant_name && t.applicant_name.includes('Mandala'))
  .sort((a, b) => new Date(b.date) - new Date(a.date));

if (!salaryTx.length) throw new Error('Kein Gehalt gefunden');

const lastSalary = salaryTx[0];
const salaryDate = lastSalary.date;
const salaryAmount = lastSalary.amount;

const after = transactions.filter(t => t.date > salaryDate);
const income = after.filter(t => t.amount > 0);
const expenses = after.filter(t => t.amount < 0);

const totalIncome = income.reduce((s, t) => s + t.amount, 0);
const totalExpenses = expenses.reduce((s, t) => s + t.amount, 0);
const grandTotal = salaryAmount + totalIncome + totalExpenses;

const fmt = (d) => { const [y,m,day]=d.split('-'); return `${day}.${m}.${y}`; };
const eur = (n) => n.toLocaleString('de-DE', {minimumFractionDigits:2, maximumFractionDigits:2});

const incomeLines = income
  .sort((a, b) => b.amount - a.amount)
  .map(t => `  +${eur(t.amount)} € — ${(t.applicant_name || t.purpose || '').substring(0,35)}`)
  .join('\n');

const topExpLines = expenses
  .sort((a, b) => a.amount - b.amount)
  .slice(0, 10)
  .map(t => {
    const desc = (t.applicant_name || t.purpose || '').substring(0,30);
    return `${eur(t.amount)} € — ${desc}`;
  })
  .join('\n');

const fazit = grandTotal >= 0
  ? `Nein, du bist noch im Plus (${eur(grandTotal)} € übrig vom Gehalt)`
  : `Ja, du hast ${eur(Math.abs(grandTotal))} € mehr ausgegeben als eingenommen`;

const msg = `💰 Monats-Finanzauswertung\n📅 seit ${fmt(salaryDate)} (letztes Gehalt)\n\nLetztes Gehalt: +${eur(salaryAmount)} € (Mandala GmbH)\n\nEinnahmen seitdem: +${eur(totalIncome)} €\n${incomeLines || '  —'}\n\nAusgaben gesamt: ${eur(totalExpenses)} €\n\nGrößte Ausgaben:\n${topExpLines}\n\nBilanz (ohne Gehalt): ${totalIncome + totalExpenses >= 0 ? '+' : ''}${eur(totalIncome + totalExpenses)} €\nBilanz (mit Gehalt): ${grandTotal >= 0 ? '+' : ''}${eur(grandTotal)} €\n\n${grandTotal >= 0 ? '✅' : '❌'} ${fazit}`;

return [{ json: { message: msg } }];

